import React, { useState, useEffect } from 'react';
import './ContactsList.css';

const ContactsList = () => {
  // Initialize state with localStorage data or default contacts
  const [contacts, setContacts] = useState(() => {
    const savedContacts = localStorage.getItem('contacts');
    return savedContacts ? JSON.parse(savedContacts) : [
      { id: 1, name: "John Doe", email: "john@example.com", phone: "555-1234" },
      { id: 2, name: "Jane Smith", email: "jane@example.com", phone: "555-5678" }
    ];
  });

  const [searchTerm, setSearchTerm] = useState('');
  const [newContact, setNewContact] = useState({ name: '', email: '', phone: '' });
  const [editingId, setEditingId] = useState(null);

  // Save contacts to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem('contacts', JSON.stringify(contacts));
  }, [contacts]);

  // Handle search filtering
  const filteredContacts = contacts.filter(contact =>
    contact.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    contact.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    contact.phone.includes(searchTerm)
  );

  // Handle adding a new contact
  const handleAddContact = (e) => {
    e.preventDefault();
    const contactToAdd = {
      ...newContact,
      id: Math.max(...contacts.map(c => c.id), 0) + 1
    };
    setContacts([...contacts, contactToAdd]);
    setNewContact({ name: '', email: '', phone: '' });
  };

  // Handle updating a contact
  const handleUpdateContact = (e) => {
    e.preventDefault();
    setContacts(contacts.map(contact =>
      contact.id === editingId ? newContact : contact
    ));
    setEditingId(null);
    setNewContact({ name: '', email: '', phone: '' });
  };

  // Handle deleting a contact
  const handleDelete = (id) => {
    setContacts(contacts.filter(contact => contact.id !== id));
  };

  // Handle editing a contact
  const handleEdit = (contact) => {
    setEditingId(contact.id);
    setNewContact(contact);
  };

  return (
    <div className="contacts-container">
      <h2>My Contacts</h2>
      
      {/* Search Input */}
      <input
        type="text"
        placeholder="Search contacts..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        className="search-input"
      />
      
      {/* Add/Edit Contact Form */}
      <form 
        onSubmit={editingId ? handleUpdateContact : handleAddContact}
        className="contact-form"
      >
        <input
          type="text"
          placeholder="Name"
          value={newContact.name}
          onChange={(e) => setNewContact({...newContact, name: e.target.value})}
          required
        />
        <input
          type="email"
          placeholder="Email"
          value={newContact.email}
          onChange={(e) => setNewContact({...newContact, email: e.target.value})}
        />
        <input
          type="tel"
          placeholder="Phone"
          value={newContact.phone}
          onChange={(e) => setNewContact({...newContact, phone: e.target.value})}
        />
        <button type="submit" className="submit-btn">
          {editingId ? 'Update Contact' : 'Add Contact'}
        </button>
        {editingId && (
          <button 
            type="button" 
            onClick={() => {
              setEditingId(null);
              setNewContact({ name: '', email: '', phone: '' });
            }}
            className="cancel-btn"
          >
            Cancel
          </button>
        )}
      </form>
      
      {/* Contacts List */}
      <div className="contacts-list">
        {filteredContacts.map(contact => (
          <div key={contact.id} className="contact-card">
            <h3>{contact.name}</h3>
            <p>Email: {contact.email}</p>
            <p>Phone: {contact.phone}</p>
            <div className="contact-actions">
              <button 
                onClick={() => handleEdit(contact)}
                className="edit-btn"
              >
                Edit
              </button>
              <button 
                onClick={() => handleDelete(contact.id)}
                className="delete-btn"
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ContactsList;
